// MVP echo + validation.
// TODO: заменить на реальную мутацию schedule.json + git commit.

const body = $input.first().json.body || {};

// Поддерживаемые поля задачи
const TASK_FIELDS = ['progress', 'actualStart', 'actualEnd', 'planStart', 'planEnd'];
// Поддерживаемые спец-операции
const OPS = ['addMilestone', 'addPhoto', 'addDelay'];

let kind = null;
let errors = [];

if (body.op) {
  if (!OPS.includes(body.op)) errors.push(`Unknown op: ${body.op}. Valid: ${OPS.join(', ')}`);
  else kind = 'op';
} else if (body.taskId && body.field) {
  if (!TASK_FIELDS.includes(body.field)) errors.push(`Unknown field: ${body.field}. Valid: ${TASK_FIELDS.join(', ')}`);
  else if (body.value === undefined) errors.push('Missing value');
  else kind = 'taskUpdate';
} else {
  errors.push('Payload must contain either {taskId, field, value} or {op, ...}');
}

const receivedAt = new Date().toISOString();

return [{
  json: {
    ok: errors.length === 0,
    kind,
    errors,
    receivedAt,
    echo: body,
    note: 'MVP skeleton — mutation/git not wired yet. See n8n/README.md roadmap.'
  }
}];
